import http from '../http'
//科室信息接口

// 科室信息列表
export function teamListAll(query: any) {
    return http.get('/jkyErp/team/getList', query)
}
// 科室信息列表
export function teamList(query: any) {
    return http.get('/jkyErp/team/list', query)
}

// 科室信息列表详细
export function getTeam(id: any) {
    return http.get('/jkyErp/team/' + id)
}
// 新增科室信息
export function addTeam(data: any) {
    return http.post('/jkyErp/team/add', data)
}

interface Editrole {
    roleId: number
    roleName: string,
    roleRemark?: string
}
// 修改科室信息
export function editTeam(data: any) {
    return http.post('/jkyErp/team/edit', data)
}

// 删除科室信息
export function delTeam(teamId: number) {
    return http.post('/jkyErp/team/del',teamId)
}

