import http from '../http'
//


// 获取全部模板
export function testportListAll(query: any) {
    return http.get('/jkyErp/testReportTemplate/getList', query)
}

// 分页查询模板
export function testportList(query: any) {
    return http.get('/jkyErp/testReportTemplate/list', query)
}

// 查询单个模板
export function gettestport(id: any) {
    return http.get('/jkyErp/testReportTemplate/' + id)
}
// 新增模板
export function addtestport(data: any) {
    return http.post('/jkyErp/testReportTemplate/add', data)
}

// 修改模板
export function editestportt(data: any) {
    return http.post('/jkyErp/testReportTemplate/edit', data)
}

// 删除模板
export function deltestport(teamId: number) {
    return http.post('/jkyErp/testReportTemplate/del',teamId)
}







