<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="产品名称"
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请选择产品类型名称"
                  v-model:value="selName"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">添加检测项</a-button>
      </a-space>
      <a-table
        :loading="loading"
        rowKey="checkItemId"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :scroll="{ y: 320 }"
      >
        <template #checkItemName="{ text, record }">
          <span :class="record.status != 0 ? 'colorCCC' : ''">{{ text }}</span>
        </template>
        <template #place="{ text, record }"
          ><span :class="record.status != 0 ? 'colorCCC' : ''">{{
            text
          }}</span></template
        >
        <template #duration="{ text, record }"
          ><span :class="record.status != 0 ? 'colorCCC' : ''">{{
            text
          }}</span></template
        >
        <template #checkPrice="{ text, record }"
          ><span v-if="text" :class="record.status != 0 ? 'colorCCC' : ''"
            >{{ text }}元</span
          ></template
        >
        <template #additionalFees="{ text, record }"
          ><span v-if="text" :class="record.status != 0 ? 'colorCCC' : ''"
            >{{ text }}元</span
          ></template
        >
        <template #logisticsCosts="{ text, record }"
          ><span v-if="text" :class="record.status != 0 ? 'colorCCC' : ''"
            >{{ text }}元</span
          ></template
        >
        <template #operation="{ record }">
          <p style="width: 260px">
            <a @click="setClick(record)">查看详情</a>&nbsp;
            <a @click="handleAddChildren(record)">添加子检测项</a>&nbsp;
            <a @click="handleUpdate(record)">编辑</a>&nbsp;
            <a-popconfirm
              :title="
                record.children
                  ? '删除该检测项其下子检测项也会被删除，您确认吗？'
                  : '您确认删除该检测项吗？'
              "
              @confirm="handleDel(record)"
            >
              <a style="color: red">删除</a>
            </a-popconfirm>
            &nbsp;
            <a
              @click="
                record.status != 0
                  ? setStatusEnable(record)
                  : setStatusDisable(record)
              "
              :class="record.status != 0 ? 'colorGreen' : 'colorRed'"
              >{{ record.status != 0 ? "启用" : "禁用" }}
            </a>
          </p>
        </template>
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="750px"
    @ok="handleOk"
    @cancel="handleCancel(1)"
  >
    <a-form :form="form">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="检测项编号">
            <a-input
              placeholder="请输入检测项编号"
              v-model:value="form.testProductItem.checkItemCode"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="检测项名称：">
            <a-input
              placeholder="请输入检测项名称"
              v-model:value="form.testProductItem.checkItemName"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="检测项模板:">
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.testProductItem.reportModelId"
              placeholder="请选择检测项模板"
            >
              <a-select-option
                v-for="item in selTestportList"
                :key="item"
                :lable="item.reportName"
                :value="item.id"
              >
                {{ item.reportName }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="实验地点">
            <a-input
              placeholder="请输入实验地点"
              v-model:value="form.testProductItem.place"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="实验时长">
            <a-input v-model:value="itemDate" placeholder="实验时长">
              <template #addonAfter>
                <a-select v-model:value="dateCompany" style="width: 100px">
                  <a-select-option value="y">y(年)</a-select-option>
                  <a-select-option value="m">m(月)</a-select-option>
                  <a-select-option value="m">m(周)</a-select-option>
                  <a-select-option value="d">d(日)</a-select-option>
                  <a-select-option value="h">h(时)</a-select-option>
                  <a-select-option value="min">min(分)</a-select-option>
                  <a-select-option value="s">s(秒)</a-select-option>
                </a-select>
              </template>
            </a-input>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="取样标准">
            <a-input
              placeholder="请输入取样标准"
              v-model:value="form.testProductItem.sampleStandard"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="取样频率">
            <a-input
              placeholder="请输入取样频率"
              v-model:value="form.testProductItem.frequency"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="取样数量：">
            <a-input v-model:value="itemWeight" placeholder="请输入取样数量">
              <template #addonAfter>
                <a-select v-model:value="weightCompany" style="width: 100px">
                  <a-select-option value="t">t(吨)</a-select-option>
                  <a-select-option value="kg">kg(千克)</a-select-option>
                  <a-select-option value="g">g(克)</a-select-option>
                </a-select>
              </template>
            </a-input>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="应用印章：">
            <a-checkbox-group v-model:value="signet">
              <a-checkbox value="CMA" name="signet">CMA</a-checkbox>
              <a-checkbox value="CNAS" name="signet">CNAS</a-checkbox>
              <a-checkbox value="甲级印章" name="signet">甲级印章</a-checkbox>
            </a-checkbox-group>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="检测价格:">
            <a-input-number
              placeholder="请输入检测价格"
              v-model:value="form.testProductItem.checkPrice"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="检测项检测依据">
            <a-select
              :allowClear="true"
              v-model:value="form.standardIds"
              mode="multiple"
              optionFilterProp="lable"
              style="width: 100%"
              placeholder="请选择检测项检测依据"
            >
              <a-select-option
                v-for="item in standardRelIdList"
                :key="item.id"
                :lable="lableSelect(item.code, item.name)"
                :value="item.id"
              >
                {{ lableSelect(item.code, item.name) }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="检测项检测的设备">
            <a-select
              :allowClear="true"
              showSearch
              mode="multiple"
              optionFilterProp="lable"
              v-model:value="form.typeIds"
              placeholder="请选择检测项检测的设备"
            >
              <a-select-option
                v-for="item in selDeviceTypeList"
                :key="item.id"
                :lable="lableSelect(item.id, item.name)"
                :value="item.id"
              >
                {{ lableSelect(item.id, item.name) }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="所属科室">
            <a-select
              :allowClear="true"
              showSearch
              mode="multiple"
              optionFilterProp="lable"
              v-model:value="form.itemIds"
              placeholder="请选择所属科室"
            >
              <a-select-option
                v-for="item in selteamList"
                :key="item.id"
                :lable="lableSelect(item.id, item.name)"
                :value="item.id"
              >
                {{ lableSelect(item.id, item.name) }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="16">
          <a-form-item label="检测项在报告中的位置坐标:">
            <a-input
              placeholder="请输入检测项在报告中的位置坐标"
              v-model:value="form.testProductItem.coordinate"
            />
          </a-form-item>
        </a-col>
        <a-col :span="8">
          <a-form-item label="检测项单位">
            <a-radio-group v-model:value="form.testProductItem.unit">
              <a-radio value="1">点</a-radio>
              <a-radio value="2">样</a-radio>
            </a-radio-group>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="技术难度">
            <a-input
              placeholder="请输入技术难度"
              v-model:value="form.testProductItem.difficulty"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="检测项图标">
            <a-upload
              v-model:file="file"
              :show-upload-list="false"
              :customRequest="customRequest"
              :before-upload="beforeUpload"
            >
              <img
                v-if="form.testProductItem.icon"
                :src="form.testProductItem.icon"
                alt="avatar"
                style="width: 100px; heidht: 100px"
              />
              <div v-else>
                <a-button>
                  <UploadOutlined></UploadOutlined>
                  点击上传检测项图标
                </a-button>
              </div>
            </a-upload>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="附加费用">
            <a-input-number
              placeholder="请输入附加费用"
              v-model:value="form.testProductItem.additionalFees"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="物流费用：">
            <a-input-number
              placeholder="请输入物流费用"
              v-model:value="form.testProductItem.logisticsCosts"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="备注">
            <a-textarea
              rows="4"
              placeholder="请输入备注"
              v-model:value="form.testProductItem.remark"
              show-count
              :maxlength="200"
            />
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
  <a-modal
    :visible="openSel"
    :title="title"
    width="750px"
    :footer="null"
    @cancel="handleCancel(0)"
  >
    <a-descriptions
      bordered
      :title="productItemSel.testProductItem.checkItemName"
      size="small"
    >
      <a-descriptions-item label="产品检测项编号">{{
        productItemSel.testProductItem.checkItemCode
      }}</a-descriptions-item>
      <a-descriptions-item label="产品检测项名称">{{
        productItemSel.testProductItem.checkItemName
      }}</a-descriptions-item>
      <a-descriptions-item label="产品检测项模板">{{
        productItemSel.reportName
      }}</a-descriptions-item>
      <a-descriptions-item label="检测项在报告中的位置坐标">{{
        productItemSel.testProductItem.coordinate
      }}</a-descriptions-item>
      <a-descriptions-item label="检测项图标">
        <img
          :src="productItemSel.testProductItem.icon"
          alt=""
          style="whild: 50px; height: 50px"
        />
      </a-descriptions-item>
      <a-descriptions-item label="附加费用"
        ><span v-if="productItemSel.testProductItem.additionalFees"
          >{{ productItemSel.testProductItem.additionalFees }}元</span
        ></a-descriptions-item
      >
      <a-descriptions-item label="物流费用"
        ><span v-if="productItemSel.testProductItem.logisticsCosts"
          >{{ productItemSel.testProductItem.logisticsCosts }}元</span
        ></a-descriptions-item
      >
      <a-descriptions-item label="技术难度">{{
        productItemSel.testProductItem.difficulty
      }}</a-descriptions-item>
      <a-descriptions-item label="检测项单位（1点，2样）">{{
        productItemSel.testProductItem.unit
      }}</a-descriptions-item>
      <a-descriptions-item label="是否有效">{{
        productItemSel.testProductItem.isAvailable == 1 ? "是" : "否"
      }}</a-descriptions-item>
      <a-descriptions-item label="实验地点">{{
        productItemSel.testProductItem.place
      }}</a-descriptions-item>
      <a-descriptions-item label="实验检测时长">{{
        productItemSel.testProductItem.duration
      }}</a-descriptions-item>
      <a-descriptions-item label="取样数量">{{
        productItemSel.testProductItem.sampleCount
      }}</a-descriptions-item>
      <a-descriptions-item label="取样频率">{{
        productItemSel.testProductItem.frequency
      }}</a-descriptions-item>
      <a-descriptions-item label="取样标准">{{
        productItemSel.testProductItem.sampleStandard
      }}</a-descriptions-item>
      <a-descriptions-item label="检测价格"
        ><span v-if="productItemSel.testProductItem.checkPrice"
          >{{ productItemSel.testProductItem.checkPrice }}元</span
        ></a-descriptions-item
      >
      <a-descriptions-item label="检测依据" :span="2">
        <p
          v-for="(items, indexs) in productItemSel.itemStandardList"
          :key="indexs"
        >
          《{{ items }}》
        </p>
      </a-descriptions-item>
      <a-descriptions-item label="检测设备">
        <p v-for="(items, indexs) in productItemSel.typeList" :key="indexs">
          {{ indexs + 1 }}、{{ items }}
        </p>
      </a-descriptions-item>
      <a-descriptions-item label="所属科室" :span="2">
        <p v-for="(items, indexs) in productItemSel.teamList" :key="indexs">
          {{ indexs + 1 }}、{{ items }}
        </p>
      </a-descriptions-item>
      <a-descriptions-item label="应用印章">
        <p v-for="(items, indexs) in methodSignet" :key="indexs">
          {{ indexs + 1 }}、{{ items }}
        </p>
      </a-descriptions-item>
      <a-descriptions-item label="备注">{{
        productItemSel.testProductItem.remark
      }}</a-descriptions-item>
    </a-descriptions>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "检测项名称",
    align: "left",
    fixed: "left",
    dataIndex: "checkItemName",
    width: 150,
    slots: { customRender: "checkItemName" },
  },
  {
    title: "实验地点",
    align: "center",
    dataIndex: "place",
    width: 80,
    slots: { customRender: "place" },
  },
  {
    title: "实验时常",
    align: "center",
    dataIndex: "duration",
    width: 80,
    slots: { customRender: "duration" },
  },
  {
    title: "检测价格",
    align: "center",
    dataIndex: "checkPrice",
    width: 80,
    slots: { customRender: "checkPrice" },
  },
  {
    title: "附加费用",
    align: "center",
    dataIndex: "additionalFees",
    width: 80,
    slots: { customRender: "additionalFees" },
  },
  {
    title: "物流费用",
    align: "center",
    dataIndex: "logisticsCosts",
    width: 80,
    slots: { customRender: "logisticsCosts" },
  },
  {
    title: "操作",
    dataIndex: "operation",
    align: "center",
    fixed: "right",
    width: 270,
    slots: { customRender: "operation" },
  },
];
import {
  itemList,
  additem,
  getitem,
  delitem,
  edititem,
  MethodListAll,
  itemListSel,
  disableItem,
  enableItem,
} from "@/server/http/api/Product";
import { testportListAll } from "@/server/http/api/testreporttemplate";
import { testListAll } from "@/server/http/api/teststand";
import { DeviceTypeListAll } from "@/server/http/api/Device";
import { teamListAll } from "@/server/http/api/team";
import { message } from "ant-design-vue";
import { uploadFile, delFile } from "@/server/http/api/File";
import { UploadOutlined } from "@ant-design/icons-vue";
export default {
  name: "QueryList",
  components: { UploadOutlined },
  props: {
    productId: 0,
  },
  data() {
    return {
      loading: false,
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      // 查看详情弹出层
      openSel: false,
      advanced: false,
      columns: columns,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {
        testProductItem: {
          checkItemId: null,
          productId: this.productId,
        },
      },
      file: null,
      Pagination: {},
      total: 0,
      queryParams: {
        productId: this.productId,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      // 检测项方法
      ProductMethodList: [],
      //检测依据
      standardRelIdList: [],
      //检测仪器分类
      selDeviceTypeList: [],
      //模板列表
      selTestportList: [],
      //所属科室
      selteamList: [],
      //记录选择的印章
      signet: [],
      //记录时间
      itemDate: null,
      //记录数量
      itemWeight: null,
      //记录时间单位
      dateCompany: "d",
      //记录计量单位
      weightCompany: "kg",
      //保存详情信息
      productItemSel: {
        testProductItem: {},
        methodList: [],
        typeList: [],
        itemStandardList: [],
        teamList: [],
      },
      //详情印章
      methodSignet: [],
      //用来存储修改的临时文件路径
      updateUrl: null,
      //模糊搜索参数
      selName: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    //this.getList();
  },
  watch: {
    productId(e) {
      (this.queryParams = {
        productId: e,
      }),
        this.getList();
    },
  },
  mounted() {
    // this.getProductMethodList();
    this.gettestListAll();
    this.getDeviceTypeList();
    this.getTestportList();
    this.getTeamList();
  },
  methods: {
    //拼接select
    lableSelect(code, name) {
      return code + " " + name;
    },
    //删除文件
    delFileMethod(e) {
      delFile({ fileUrl: e }).then((res) => {});
    },
    //查看详情按钮
    setClick(e) {
      itemListSel({
        checkItemId: e.checkItemId,
        productId: this.queryParams.productId,
      }).then((res) => {
        var data = res.data;
        this.productItemSel = data.data[0];
        if (this.productItemSel.testProductItem.methodSignet) {
          this.methodSignet =
            this.productItemSel.testProductItem.methodSignet.split(",");
        }
        this.openSel = true;
      });
    },
    //检测项图标上传
    customRequest(info) {
      const formData = new FormData();
      formData.append("file", info.file);
      if (
        this.form.testProductItem.icon != null &&
        this.updateUrl != this.form.testProductItem.icon
      ) {
        this.delFileMethod(this.form.testProductItem.icon);
      }
      uploadFile(formData).then((res) => {
        this.form.testProductItem.icon = res.data.data.fileUrl;
      });
    },
    //检测项图标上传前
    beforeUpload(file) {
      const isJpgOrPng =
        file.type === "image/jpeg" || file.type === "image/png";
      if (!isJpgOrPng) {
        message.error("只能上传图片!");
      }
      const isLt5M = file.size / 1024 / 1024 < 5;

      if (!isLt5M) {
        message.error("图片大小不能超过5M!");
      }
      return isJpgOrPng && isLt5M;
    },
    //获取模板列表方法
    getTestportList() {
      testportListAll().then((res) => {
        var data = res.data;
        this.selTestportList = data.data;
      });
    },
    //获取检查项检测方法
    getProductMethodList() {
      MethodListAll().then((res) => {
        var data = res.data;
        this.ProductMethodList = data.data;
      });
    },
    //获取检测依据
    gettestListAll() {
      testListAll({ type: 2 }).then((res) => {
        this.standardRelIdList = res.data.data;
      });
    },
    //获取仪器分类
    getDeviceTypeList() {
      DeviceTypeListAll().then((res) => {
        var data = res.data;
        this.selDeviceTypeList = data.data;
      });
    },
    //获取科室列表
    getTeamList() {
      teamListAll().then((res) => {
        var data = res.data;
        this.selteamList = data.data;
      });
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      this.loading=true;
      itemList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = this.getChildren(data.data, this.selName);
      });
    },
    //children递归
    getChildren(e, val) {
      for (let index = 0; index < e.length; index++) {
        const element = e[index];
        if (element.children.length != 0) {
          this.getChildren(element.children);
        } else {
          delete element.children;
        }
      }
      if (val && val != "") {
        return this.onRecursionData(e, val);
      } else {
        this.loading=false;
        return e;
      }
    },
    //递归搜索
    onRecursionData(arr, val) {
      let newarr = [];
      arr.forEach((item) => {
        if (item.children && item.children.length) {
          let children = this.onRecursionData(item.children, val);
          let obj = {
            ...item,
            children,
          };
          if (children && children.length) {
            newarr.push(obj);
          } else if (item.checkItemName.includes(val)) {
            newarr.push({ ...item });
          }
        } else {
          if (item.checkItemName.includes(val)) {
            newarr.push(item);
          }
        }
      });
      this.loading=false;
      return newarr;
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    handleOk(e) {
      this.submitForm();
    },
    handleCancel(e) {
      if (
        this.form.testProductItem.icon != null &&
        this.updateUrl != this.form.testProductItem.icon &&
        e == 1
      ) {
        this.delFileMethod(this.form.testProductItem.icon);
      }
      this.updateUrl = null;
      this.itemDate = null;
      this.itemWeight = null;
      this.dateCompany = "d";
      this.weightCompany = "kg";
      this.signetList = [];
      this.signet = [];
      this.form = {
        testProductItem: {
          checkItemId: null,
          productId: this.productId,
        },
      };
      this.methodSignet = [];
      (this.productItemSel = {
        testProductItem: {},
        methodList: [],
        typeList: [],
        itemStandardList: [],
        teamList: [],
      }),
        (this.open = false);
      this.openSel = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.open = true;
      this.title = "添加检测项";
    },
    /** 新增子类按钮 */
    handleAddChildren(e) {
      this.title = "添加子检测项";
      this.form.testProductItem.checkItemPid = e.checkItemId;
      this.open = true;
    },
    /** 修改按钮操作 */
    handleUpdate(e) {
      this.open = true;
      this.title = "修改检测项";
      getitem(e.checkItemId).then((response) => {
        this.form = response.data.data;
        //回显印章默认选项
        if (this.form.testProductItem.methodSignet) {
          this.signet = this.form.testProductItem.methodSignet.split(",");
        }
        //回显时间和时间单位
        if (this.form.testProductItem.duration) {
          this.dateCompany = this.form.testProductItem.duration.replace(
            /[^a-z]+/gi,
            ""
          );
          this.itemDate = this.form.testProductItem.duration.replace(
            /[^0-9]/gi,
            ""
          );
        }
        //回显数量和计量单位
        if (this.form.testProductItem.sampleCount) {
          this.weightCompany = this.form.testProductItem.sampleCount.replace(
            /[^a-z]+/gi,
            ""
          );
          this.itemWeight = this.form.testProductItem.sampleCount.replace(
            /[^0-9]/gi,
            ""
          );
        }
        this.updateUrl = this.form.testProductItem.icon;
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.signet.length != 0) {
        this.form.testProductItem.methodSignet = this.signet.toString();
      }
      if (this.itemDate != "" && this.itemDate != null) {
        this.form.testProductItem.duration = this.itemDate + this.dateCompany;
      }
      if (this.itemWeight != "" && this.itemWeight != null) {
        this.form.testProductItem.sampleCount =
          this.itemWeight + this.weightCompany;
      }
      if (this.form.testProductItem.checkItemId != null) {
        if (this.form.testProductItem.icon != this.updateUrl) {
          this.delFileMethod(this.updateUrl);
        }
        edititem(this.form)
          .then((response) => {
            this.handleCancel(0);
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        additem(this.form)
          .then((response) => {
            this.handleCancel(0);
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    //删除
    handleDel(e) {
      delitem([e.checkItemId])
        .then((response) => {
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
    //禁用
    setStatusDisable(e) {
      disableItem([e.checkItemId])
        .then((response) => {
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
    //启用
    setStatusEnable(e) {
      enableItem([e.checkItemId])
        .then((response) => {
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

